VALUES
  ('pukao-6f0ba476-moex-00059', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依現行所得稅法之規定，營利事業交易105年1月1日以後取得之房屋、土地，其交易所得之課 徵，下列敘述何者正確？', '["獨資、合夥組織之營利事業交易房屋、土地，其交易所得應計入獨資、合夥組織營利事業之所 得額，交易損失得自3年內純益中扣除", "我國甲公司交易其非以起造人名義取得之房屋、土地，其交易所得不併計營利事業所得額，分 開計稅，分開報繳", "我國乙公司交易其以起造人申請建物所有權第一次登記所取得之房屋及其坐落基地，其交易所 得應併計營利事業所得額結算申報，交易損失得自3年內純益中扣除", "外國A公司110年初持有我國丙公司100%股權，丙公司的資本額中有80%是由境內不動產所 構成，外國A公司於114年初將持有丙公司之股權全部出售給我國某上市公司，則外國 A公 司出售股權之所得應繳納我國所得稅，稅率為35%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00060', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依土地稅法及相關法令之規定，下列敘述何者錯誤？', '["累進起點地價，以各該直轄縣市或縣（市）土地七公畝之平均地價為準", "土地為信託財產者，於信託關係存續中，以受託人為納稅義務人", "納稅義務人行蹤不明者，主管稽徵機關得指定土地使用人負責代繳其使用部分之地價稅", "無償供公眾通行之道路土地，經查明屬實者，在使用期間內，地價稅按千分之二稅率徵收"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00061', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依土地稅法及相關稅法之規定，下列那些情況於土地移轉時，得申請不課徵土地增值稅？①交換', '["土地設定典權時", "配偶相互贈與土地時", "作農業使用之農業用地，移轉於自然人 時  ⑤遺贈土地", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00062', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依土地稅法及相關法令規定，下列那些情況，土地所有權人不可以申請退還所繳納土地增值稅？', '["自用住宅3公畝用地出售後另行購買2公畝自用住宅用地", "公司投資之土地出售後另行購買 之土地", "自營工廠用地出售後另行購買自營工廠用地", "自耕農業用地出售後另行購買自耕 農業用地  ⑤自營店面用地出售後另行購買自營店面用地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00063', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依遺產及贈與稅法之規定，下列那些項目須計入贈與總額，核課贈與稅？①捐贈給公股持股40%', '["捐贈給國立大學", "捐贈給祭祀公業之財產", "以顯著不相當之代價讓與財產 ⑤叔姪間買賣國內不動產，未能提出支付價款之確實證明  ⑥信託契約明定全部信託利益之受益 人為委託人", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00064', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '個人辦理綜合所得稅結算申報時，依所得基本稅額條例現行之規定，下列那些項目應計入基本所得', '["出售美國公司發行股票獲利新臺幣 110 萬元", "出售我國私募證券投資信託基金之受益證 券，獲利新臺幣50萬元", "申報綜合所得稅時減除之現金捐贈新臺幣80萬元", "個人出售我國之 未上市櫃公司股票交易所得 200 萬元  ⑤綜合所得稅結算申報選擇股利及盈餘採分開計稅之合計 金額  ⑥營利事業依運動產業發展條例之規定，對運動賽事主辦單位之捐贈金額加成減除金額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00065', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '按現行稅捐稽徵法之退稅相關規定，納稅人因自身誤用法令而溢繳稅款，得自繳納之日起，幾年 內提出具體證明，申請退還？', '["無期限限制", "5年", "10年", "15年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00066', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '納稅義務人因受天災影響，不能於法定期間內繳清稅捐者，可向稅稽徵機關申請分期繳納，按稅 捐稽徵法第26條規定，分期的期限最多不可超過幾年？', '["1年", "2年", "3年", "5年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00067', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '稅捐稽徵法之相關規定，下列何者正確？', '["財政部依稅捐稽徵法或稅法所發布之解釋函令，對於據以申請但尚未核課確定之案件均發生效力", "財政部發布之稅務違章案件裁罰金額或倍數參考表變更時，對於尚未核課確定之案件均發生效力", "稅捐稽徵機關對於按納稅義務人申報資料核定之案件，得以公告方式，代替核定稅額通知書之 填具及送達", "租稅行政罰以故意或過失為要件，由法院判決處罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00068', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '下列何者基本上並非稅捐稽徵法中所列依「稅籍底冊或查得資料核定」課徵之稅捐？', '["地價稅", "土地增值稅", "房屋稅", "查定課徵之營業稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
